**Approach:** Iterate through the items, maintaining a current chunk. For each new element, check if it satisfies the predicate with the last element of the current chunk—if yes, add it to the chunk; if no, finalize the current chunk and start a new one.

```rust
fn chunk_by<T, F>(items: Vec<T>, predicate: F) -> Vec<Vec<T>>
where
    F: Fn(&T, &T) -> bool,
{
    if items.is_empty() {
        return vec![];
    }

    let mut chunks: Vec<Vec<T>> = vec![];
    let mut iter = items.into_iter();
    let mut current_chunk = vec![iter.next().unwrap()];

    for item in iter {
        // Check if current item belongs to the current chunk
        if predicate(current_chunk.last().unwrap(), &item) {
            current_chunk.push(item);
        } else {
            // Start a new chunk
            chunks.push(current_chunk);
            current_chunk = vec![item];
        }
    }

    // Push the final chunk
    chunks.push(current_chunk);
    chunks
}

